        ctx.translate(this.x + TILE_SIZE/2, this.y + TILE_SIZE/2);
        ctx.rotate(this.rotation);

        const mouthAngle = 0.2 * Math.PI * (0.1 + 0.9 * this.mouthOpen); // Smooth mouth

        ctx.beginPath();
        ctx.arc(0, 0, this.radius, mouthAngle, 2 * Math.PI - mouthAngle);
        ctx.lineTo(0, 0);
        ctx.fillStyle = '#FFD700';
        ctx.shadowColor = '#FFD700';
        ctx.shadowBlur = 10;
        ctx.fill();
        ctx.closePath();

        ctx.restore();
    }
}

class Ghost extends Entity {
    constructor(type, color, startX, startY) {
        super(startX * TILE_SIZE, startY * TILE_SIZE, type === 'blinky' ? 1.4 : 1.3); // Blinky is slightly faster
        this.type = type; // blinky, pinky, inky, clyde
        this.color = color;
        this.originalColor = color;
        this.mode = 'SCATTER'; // SCATTER, CHASE, FRIGHTENED, EATEN, HOUSE
        this.target = { x: 0, y: 0 };

        // Animation
        this.animFrame = 0;
    }

    update() {
        this.move();
        this.animFrame++;

        // Mode switching logic could go here (timer based)
        if (this.mode === 'FRIGHTENED') {
            if (frameCount % 600 === 0) { // Approx 10 sec
                this.setMode('CHASE');
            }
        }

        // AI Decision Making at Intersections
        if (this.isCentered()) {
            const tile = this.getTile();

            // If returning to house, handle door entry
            if (this.mode === 'EATEN') {
                if (tile.r === 14 && tile.c >= 10 && tile.c <= 17) { // At door
                    this.y += this.speed; // Force down into house
                    if (tile.r > 16) {
                        this.setMode('HOUSE'); // Respawn logic
                    }
                    return;
                }
            }

            // Choose best direction
            const options = [];
            [UP, DOWN, LEFT, RIGHT].forEach(d => {
                // Cannot reverse immediately unless frightened or eaten
                if (d.x === -this.dir.x && d.y === -this.dir.y && this.mode !== 'FRIGHTENED' && this.mode !== 'EATEN') return;

                if (this.canMove(d)) options.push(d);
            });

            if (options.length > 0) {
                // Calculate target based on mode
                this.calculateTarget();

                let bestDir = options[0];
                let minDist = Infinity;

                if (this.mode === 'FRIGHTENED') {
                    // Random choice
                    bestDir = options[Math.floor(Math.random() * options.length)];
                } else {
                    // Euclidean distance to target
                    options.forEach(opt => {
                        const nextR = tile.r + opt.y;
                        const nextC = tile.c + opt.x;
                        const dist = Math.hypot(nextC - this.target.x, nextR - this.target.y);
                        if (dist < minDist) {
                            minDist = dist;
                            bestDir = opt;
                        }
                    });
                }

                // Apply direction
                this.dir = bestDir;
            } else {
                // Dead end (shouldn't happen in standard map often), reverse
                this.dir = { x: -this.dir.x, y: -this.dir.y };
            }
        }

        // Collision with Pacman
        const dx = this.x - pacman.x;
        const dy = this.y - pacman.y;
        if (Math.sqrt(dx*dx + dy*dy) < TILE_SIZE * 0.8) {
            if (this.mode === 'FRIGHTENED') {
                // Eat Ghost
                score += 200;
                showFloatingText("200", this.x, this.y);
                this.setMode('EATEN');
                // Sound placeholder: playEatGhostSound()
            } else if (this.mode !== 'EATEN' && this.mode !== 'HOUSE') {
                // Pacman dies
                handleDeath();
            }
        }
    }

    setMode(newMode) {
        this.mode = newMode;
        if (newMode === 'EATEN') {
            this.speed = 2.5; // Fast return
        } else if (newMode === 'FRIGHTENED') {
            this.speed = 1.0; // Slow down
            // Reverse immediately on power pellet
            this.dir = { x: -this.dir.x, y: -this.dir.y };
        } else {
            this.speed = (this.type === 'blinky') ? 1.4 : 1.3;
        }
    }

    calculateTarget() {
        const pTile = pacman.getTile();

        if (this.mode === 'EATEN') {
            this.target = { x: 14, y: 14 }; // Ghost house door
            return;
        }

        if (this.mode === 'SCATTER') {
            // Corners
            if (this.type === 'blinky') this.target = { x: 25, y: 0 };
            else if (this.type === 'pinky') this.target = { x: 2, y: 0 };
            else if (this.type === 'inky') this.target = { x: 27, y: 30 };
            else if (this.type === 'clyde') this.target = { x: 0, y: 30 };
            return;
        }

        // CHASE MODE
        if (this.type === 'blinky') {
            // Direct chase
            this.target = { x: pTile.c, y: pTile.r };
        } 
        else if (this.type === 'pinky') {
            // Ambush: 4 tiles in front of Pacman
            this.target = { 
                x: pTile.c + (pacman.dir.x * 4), 
                y: pTile.r + (pacman.dir.y * 4) 
            };
        } 
        else if (this.type === 'inky') {
            // Flank: Complex vector based on Blinky
            const blinky = ghosts[0];
            this.target = { 
                x: pTile.c + (pacman.dir.x * 2), 
                y: pTile.r + (pacman.dir.y * 2) 
            };
            // Rotate vector around Pacman by 180 and add Blinky pos? 
            // Simplified: Target is the tile double the distance from Blinky to Pacman's offset
            this.target.x += (this.target.x - blinky.getTile().c);
            this.target.y += (this.target.y - blinky.getTile().r);
        } 
        else if (this.type === 'clyde') {
            // Erratic: Chase unless close
            const dist = Math.hypot(this.getTile().c - pTile.c, this.getTile().r - pTile.r);
            if (dist > 8) {
                this.target = { x: pTile.c, y: pTile.r };
            } else {
                this.target = { x: 0, y: 30 }; // Scatter corner
            }
        }
    }

    draw() {
        const cx = this.x + TILE_SIZE/2;
        const cy = this.y + TILE_SIZE/2;

        ctx.fillStyle = (this.mode === 'FRIGHTENED') 
            ? (frameCount % 20 < 10 ? '#FFFFFF' : '#0000FF') // Flash white near end
            : (this.mode === 'EATEN' ? 'rgba(0,0,0,0)' : this.color);

        if (this.mode !== 'EATEN') {
            // Draw Body (Dome + Skirt)
            ctx.beginPath();
            ctx.arc(cx, cy - 2, this.radius, Math.PI, 0);
            ctx.lineTo(cx + this.radius, cy + this.radius);

            // Wiggly feet
            const wave = Math.sin(this.animFrame * 0.5) * 2;
            ctx.lineTo(cx + this.radius/3, cy + this.radius - wave);
            ctx.lineTo(cx - this.radius/3, cy + this.radius + wave);
            ctx.lineTo(cx - this.radius, cy + this.radius);

            ctx.fill();
            ctx.closePath();

            // Eyes
            if (this.mode !== 'FRIGHTENED') {
                ctx.fillStyle = 'white';
                const eyeOffX = this.dir.x * 2;
                const eyeOffY = this.dir.y * 2;

                ctx.beginPath(); ctx.arc(cx - 4 + eyeOffX, cy - 5 + eyeOffY, 3, 0, Math.PI*2); ctx.fill();
                ctx.beginPath(); ctx.arc(cx + 4 + eyeOffX, cy - 5 + eyeOffY, 3, 0, Math.PI*2); ctx.fill();

                // Pupils
                ctx.fillStyle = 'blue';
                ctx.beginPath(); ctx.arc(cx - 4 + eyeOffX*1.5, cy - 5 + eyeOffY*1.5, 1.5, 0, Math.PI*2); ctx.fill();
                ctx.beginPath(); ctx.arc(cx + 4 + eyeOffX*1.5, cy - 5 + eyeOffY*1.5, 1.5, 0, Math.PI*2); ctx.fill();
            } else {
                // Frightened Face
                ctx.fillStyle = '#ffccaa';
                ctx.fillRect(cx - 4, cy - 2, 2, 2);
                ctx.fillRect(cx + 2, cy - 2, 2, 2);
                ctx.strokeStyle = '#ffccaa';
                ctx.beginPath(); ctx.moveTo(cx - 5, cy + 3); ctx.lineTo(cx - 2, cy + 5); ctx.stroke();
                ctx.beginPath(); ctx.moveTo(cx + 5, cy + 3); ctx.lineTo(cx + 2, cy + 5); ctx.stroke();
            }
        } else {
            // Just Eyes returning to house
            ctx.fillStyle = 'white';
            ctx.beginPath(); ctx.arc(cx - 4, cy - 2, 3, 0, Math.PI*2); ctx.fill();
            ctx.beginPath(); ctx.arc(cx + 4, cy - 2, 3, 0, Math.PI*2); ctx.fill();
            // Pupils look towards center
            const dx = 14 - this.getTile().c;
            const dy = 14 - this.getTile().r;
            const angle = Math.atan2(dy, dx);
            ctx.fillStyle = 'blue';
            ctx.beginPath(); ctx.arc(cx - 4 + Math.cos(angle)*2, cy - 2 + Math.sin(angle)*2, 1.5, 0, Math.PI*2); ctx.fill();
            ctx.beginPath(); ctx.arc(cx + 4 + Math.cos(angle)*2, cy - 2 + Math.sin(angle)*2, 1.5, 0, Math.PI*2); ctx.fill();
        }
    }
}

class Fruit {
    constructor() {
        this.x = TILE_SIZE * 14;
        this.y = TILE_SIZE * 17; // Just below ghost house
        this.active = false;
        this.points = 100;
        this.type = 'cherry'; // cherry, strawberry, etc.
    }

    spawn() {
        if (!this.active && dotsRemaining > 0) {
            this.active = true;
            // Cycle fruit based on level
            if (level === 1) { this.type = 'cherry'; this.points = 100; }
            else if (level === 2) { this.type = 'strawberry'; this.points = 300; }
            else { this.type = 'peach'; this.points = 500; }

            // Despawn after timer
            setTimeout(() => { this.active = false; }, 8000);
        }
    }

    draw() {
        if (!this.active) return;

        ctx.save();
        ctx.translate(this.x + TILE_SIZE/2, this.y + TILE_SIZE/2);

        if (this.type === 'cherry') {
            ctx.fillStyle = 'red';
            ctx.beginPath(); ctx.arc(-3, 0, 4, 0, Math.PI*2); ctx.fill();
            ctx.beginPath(); ctx.arc(3, 0, 4, 0, Math.PI*2); ctx.fill();
            ctx.strokeStyle = 'green'; ctx.beginPath(); ctx.moveTo(-3,-3); ctx.lineTo(0,-6); ctx.lineTo(3,-3); ctx.stroke();
        } else if (this.type === 'strawberry') {
            ctx.fillStyle = '#ff5555';
            // Triangle shape with seeds
            ctx.beginPath();
            ctx.ellipse(0, 2, 4, 6, 0, 0, Math.PI*2);
            ctx.fill();
            ctx.fillStyle = 'yellow'; // Seeds
            ctx.fillRect(-1, 0, 1, 1); ctx.fillRect(1, 2, 1, 1);
        } else {
            ctx.fillStyle = '#ffcc99';
            ctx.beginPath(); ctx.arc(0, 0, 5, 0, Math.PI*2); ctx.fill();
            ctx.fillStyle = 'red'; ctx.fillRect(-2, -6, 4, 3);
        }

        ctx.restore();
    }
}

