// --- RENDERING ---

function drawMap() {
    // Draw Walls
    ctx.strokeStyle = '#1919A6';
    ctx.lineWidth = 2;
    ctx.lineCap = 'round';

    // Optimization: Instead of iterating every pixel, we iterate grid.
    // To make it look like "Great Graphics", we draw lines connecting centers of wall tiles.
    // However, for a single file simple implementation, drawing blocks with rounded corners or paths is safer.
    // Let's do the classic hollow line style.

    ctx.beginPath();
    for (let r = 0; r < map.length; r++) {
        for (let c = 0; c < map[r].length; c++) {
            if (map[r][c] === T_WALL) {
                const x = c * TILE_SIZE + TILE_SIZE/2;
                const y = r * TILE_SIZE + TILE_SIZE/2;

                // Draw a block for the wall
                ctx.fillStyle = 'black';
                ctx.fillRect(c*TILE_SIZE, r*TILE_SIZE, TILE_SIZE, TILE_SIZE);

                // Draw blue border
                ctx.strokeRect(c*TILE_SIZE+1, r*TILE_SIZE+1, TILE_SIZE-2, TILE_SIZE-2);
            }
