// --- MAIN LOOP ---

function gameLoop() {
    if (gameState !== STATE_PLAYING) return;

    // Clear
    ctx.fillStyle = 'black';
    ctx.fillRect(0, 0, CANVAS_W, CANVAS_H);

    frameCount++;

